function getFirstElement<T>(arr: T[]): T {
  return arr[0];
}

const numbers = [1, 2, 3];
const firstNumber = getFirstElement(numbers); // firstNumber is number

const strings = ['a', 'b', 'c'];
const firstString = getFirstElement(strings); // firstString is string

interface Box<T> {
  contents: T;
}

const numberBox: Box<number> = { contents: 123 };
const stringBox: Box<string> = { contents: 'hello' };

interface HasLength {
  length: number;
}

function printLength<T extends HasLength>(input: T): void {
  console.log(input.length);
}

printLength('hello'); // 5
printLength([1, 2, 3]); // 3
// printLength(42); // Error: number doesn't have length

